            return false;
        }
        // Check first 10 bytes are 0
        for (int i = 0; i < 10; i++) {
            if (bytes[i] != 0) {
                return false;
            }
        }
        // Check bytes 10-11 are 0xff
        return bytes[10] == (byte) 0xFF && bytes[11] == (byte) 0xFF;
    }
