                    byte[] ipv4Bytes = new byte[4];
                    System.arraycopy(bytes, 12, ipv4Bytes, 0, 4);
                    InetAddress ipv4 = InetAddress.getByAddress(ipv4Bytes);
                    // Only block if the embedded IPv4 is not 0.0.0.0
                    if (ipv4Bytes[0] != 0 || ipv4Bytes[1] != 0 || ipv4Bytes[2] != 0 || ipv4Bytes[3] != 0) {
                        return isInternalOrReservedIp(ipv4);
                    }
                } catch (UnknownHostException e) {
                    return true;
                }
            }

