                (bytes[2] & 0xFF) == 0x0d && (bytes[3] & 0xFF) == 0xb8) {
                return true;
            }

            // Deprecated site-local addresses fec0::/10
            if ((bytes[0] & 0xFF) == 0xfe && (bytes[1] & 0xC0) == 0xc0) {
                return true;
            }
        }

        return false;
    }

    /**
     * Check if IPv6 address is IPv4-mapped (::ffff:0:0/96)
     */
    private boolean isIPv4MappedIPv6(byte[] bytes) {
        // First 10 bytes must be 0, bytes 10-11 must be 0xFF
        for (int i = 0; i < 10; i++) {
            if (bytes[i] != 0) {
                return false;
            }
        }
        return (bytes[10] & 0xFF) == 0xFF && (bytes[11] & 0xFF) == 0xFF;
    }

    /**
     * Check if IPv6 address is IPv4-compatible (::/96) - deprecated
     */
    private boolean isIPv4CompatibleIPv6(byte[] bytes) {
        // First 12 bytes must be 0
        for (int i = 0; i < 12; i++) {
            if (bytes[i] != 0) {
                return false;
            }
        }
        return true;
    }
